import{c as a,bn as d,aU as r,aX as e,z as h,a4 as l}from"./chunks/framework.BZ6QiwKG.js";const _=JSON.parse('{"title":"九佑","description":"","frontmatter":{"order":2},"headers":[],"relativePath":"地图/弥天神域/九佑.md","filePath":"地图/弥天神域/九佑.md","lastUpdated":0}'),b={name:"地图/弥天神域/九佑.md"};function i(o,t,n,s,c,m){return d(),r("div",null,[...t[0]||(t[0]=[e('<h1 id="九佑" tabindex="-1">九佑 <a class="header-anchor" href="#九佑" aria-label="Permalink to “九佑”">​</a></h1><h2 id="小怪掉落" tabindex="-1">小怪掉落 <a class="header-anchor" href="#小怪掉落" aria-label="Permalink to “小怪掉落”">​</a></h2><table tabindex="0"><thead><tr><th>材料</th></tr></thead><tbody><tr><td>九佑玄晶</td></tr></tbody></table><h2 id="逆星台" tabindex="-1">逆星台 <a class="header-anchor" href="#逆星台" aria-label="Permalink to “逆星台”">​</a></h2><h3 id="哈奴曼" tabindex="-1">哈奴曼 <a class="header-anchor" href="#哈奴曼" aria-label="Permalink to “哈奴曼”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>旋风重击：舞动如意棍不断旋转，快速移动至敌人方向，挥动如意棍朝下重劈、砸地爆炸</td></tr><tr><td>一棍定音：将如意棍丢至屏幕最高处，定位玩家Y轴，如意棍化为粗大的巨影，从天空砸向地面</td></tr><tr><td>无情三斩：挥舞如意棍，横扫出一道棍影，竖劈一道棍影，转动如意棍，触发爆炸十字</td></tr><tr><td>回旋棍： 甩出如意棍，如意棍旋转成一道金色光圈，在场景中旋转数圈</td></tr><tr><td>乾坤棍影：挥舞棍在面前画出一个施法光影圈，从圈中射出5道棍影，穿刺前方敌人</td></tr><tr><td>神猴变身：假死，瘫倒在地。突然从地面弹跳至半空，化为神·哈奴曼</td></tr></tbody></table><h3 id="神·哈奴曼" tabindex="-1">神·哈奴曼 <a class="header-anchor" href="#神·哈奴曼" aria-label="Permalink to “神·哈奴曼”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>腾云：坐在云雾上飞速移动至敌人处，挥动数只手臂向前连续攻击数拳</td></tr><tr><td>无影掌：手掌轮番推出掌印，追踪玩家，每被击中1次获得1层状态，叠加5次状态后，被原地禁锢2秒</td></tr><tr><td>风之子：身前召唤出一团风暴，在场景地面上来回移动，玩家碰到风暴会被击飞</td></tr><tr><td>狂暴风柱： 定位玩家位置，地面预警1秒，从地面召唤一条风柱，共5次</td></tr><tr><td>风暴漩涡：在BOSS位置生成一个漩涡，BOSS消失。后场景中生成3个漩涡，牵引玩家并造成伤害，BOSS随机出现在一个漩涡处</td></tr><tr><td>云盾：团坐的云雾消散，化为白色护盾，笼罩哈奴曼，恢复生命。对哈奴曼猛攻，可打碎护盾恢复效果 （高等级的技能（15级及以上）才能对该护盾造成伤害；低级技能攻击时，提示文字【抵挡】，无法对护盾造成伤害</td></tr><tr><td>神猴狂怒：进入暴怒状态，此时攻击哈奴曼会使他大幅提高暴击和闪避</td></tr></tbody></table><table tabindex="0"><thead><tr><th>掉落材料</th><th>掉落装备</th></tr></thead><tbody><tr><td>九佑莲叶</td><td>九佑魂珏</td></tr></tbody></table><h2 id="碧落海" tabindex="-1">碧落海 <a class="header-anchor" href="#碧落海" aria-label="Permalink to “碧落海”">​</a></h2><h3 id="吉祥天女" tabindex="-1">吉祥天女 <a class="header-anchor" href="#吉祥天女" aria-label="Permalink to “吉祥天女”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>飞箭：手中羽箭朝玩家飞掷</td></tr><tr><td>箭雨：手中的羽箭飞至头顶旋转，从屏幕外召唤出数枚羽箭穿刺玩家</td></tr><tr><td>飞花：手中的莲花发光数次，幻化为8朵半透明莲花，呈放射状飞射</td></tr><tr><td>莲射：朝敌人当前所在位置发射莲花，莲花会一直停留在场上 莲·收--将场上所有的莲花召回，对沿途的敌人造成伤害</td></tr><tr><td>怒目：BOSS第三只眼睛闪亮，在人物身前幻化出第三只眼，对人物发射金光，中招后大幅降低玩家命中</td></tr><tr><td>被动技：脚下的莲花花瓣展开，飞速旋转，此时攻击BOSS会被反伤</td></tr></tbody></table><table tabindex="0"><thead><tr><th>掉落材料</th><th>掉落装备</th></tr></thead><tbody><tr><td>九佑莲刺</td><td>九佑魂锥</td></tr></tbody></table><h2 id="碧落海隐藏" tabindex="-1">碧落海隐藏 <a class="header-anchor" href="#碧落海隐藏" aria-label="Permalink to “碧落海隐藏”">​</a></h2><p>在两个珍珠这里<strong>向左走</strong>就可以找到<strong>隐藏入口</strong></p><img src="'+h+'" alt="碧落海隐藏" style="zoom:50%;"><h3 id="海皇摩蹉" tabindex="-1">海皇摩蹉 <a class="header-anchor" href="#海皇摩蹉" aria-label="Permalink to “海皇摩蹉”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>禁锢泡泡：吹出一个慢慢变大的泡泡，朝着目标区域施放，包裹住敌人，造成伤害并禁锢</td></tr><tr><td>海洋佣兵：晃动海螺，在场中上下左右角落出现4个黑色漩涡，从漩涡中召唤出4个电鳗</td></tr><tr><td>海皇号令：吹响海螺，出现波纹预警，之后召唤出一头巨大的鲨鱼幻影，从玩家所在位置张大巨嘴破空而出</td></tr><tr><td>泣泪成珠：举起珍珠飞轮，朝四周释放珍珠子弹</td></tr><tr><td>狂狼海啸：甩动鱼尾，在场景中掀起一道浪潮，从左至右拍打全屏</td></tr><tr><td>海皇宝座：海皇瞬移到宝座上，汇聚珍珠能量为海皇恢复生命。攻击宝座，珍珠受到一定攻击后，失去能量</td></tr></tbody></table><table tabindex="0"><thead><tr><th>掉落材料</th><th>掉落装备</th></tr></thead><tbody><tr><td>九佑莲蕊</td><td>九佑魂环</td></tr></tbody></table><h2 id="浩瀚舍沙" tabindex="-1">浩瀚舍沙 <a class="header-anchor" href="#浩瀚舍沙" aria-label="Permalink to “浩瀚舍沙”">​</a></h2><h3 id="毗湿奴" tabindex="-1">毗湿奴 <a class="header-anchor" href="#毗湿奴" aria-label="Permalink to “毗湿奴”">​</a></h3><table tabindex="0"><thead><tr><th>技能</th></tr></thead><tbody><tr><td>巨蛇撕咬：蛇头撕咬</td></tr><tr><td>球状毒囊：蛇头轮流朝敌人吐小毒球，附带中毒效果</td></tr><tr><td>毒液喷射：所有蛇头朝下方喷溅毒液，之后毒液在前方如雨般落下，滴落在地板上</td></tr><tr><td>天权神锤：手持神锤敲击近前玩家，造成晕眩</td></tr><tr><td>回旋圆轮：朝玩家方向投掷回旋圆轮，对碰到的玩家造成禁锢效果</td></tr><tr><td>弥天毒雾：所有蛇头朝毗湿奴喷射绿色雾气，一层浓郁的绿色毒罩包裹毗湿奴。攻击毗湿奴会被反噬中毒</td></tr></tbody></table><table tabindex="0"><thead><tr><th>掉落材料</th><th>掉落装备</th></tr></thead><tbody><tr><td>九佑莲子</td><td>九佑魂铃</td></tr></tbody></table><h2 id="法宝" tabindex="-1">法宝 <a class="header-anchor" href="#法宝" aria-label="Permalink to “法宝”">​</a></h2><h3 id="九佑魂莲" tabindex="-1">九佑魂莲 <a class="header-anchor" href="#九佑魂莲" aria-label="Permalink to “九佑魂莲”">​</a></h3><img src="'+l+'" alt="九佑魂莲" style="zoom:50%;"><table tabindex="0"><thead><tr><th>被动</th><th>属性</th></tr></thead><tbody><tr><td>回血</td><td>13~18</td></tr><tr><td>回魔</td><td>8~11</td></tr></tbody></table>',27)])])}const y=a(b,[["render",i]]);export{_ as __pageData,y as default};
